process.on('uncaughtException', (err) => { console.error(err); process.exit(1); });
```

## 2. No Input Validation on Routes

**Issue:** Current routes accept no user input, but as soon as you add `/users/:id` or query params, you need validation. Build the habit now.

**Fix:** Use a schema validator (e.g., `zod`, `joi`, or `express-validator`):

```js
const { z } = require('zod');

const idSchema = z.coerce.number().int().positive();

app.get('/users/:id', (req, res, next) => {
  const parsed = idSchema.safeParse(req.params.id);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid id' });
  // ... lookup user with parsed.data
});
```

## 3. Missing Security Middleware

**Issue:** No `helmet` (security headers), no CORS policy, no rate limiting, no body-size limit.

**Fix:**

```js
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');

app.use(helmet());
app.use(cors({ origin: process.env.ALLOWED_ORIGIN, methods: ['GET'] }));
app.use(express.json({ limit: '10kb' })); // cap body size
app.use(rateLimit({ windowMs: 60_000, max: 100 }));
app.disable('x-powered-by'); // helmet does this, but explicit is fine
```

## 4. PII Exposure on `/users`

**Issue:** `/users` returns email addresses with no authentication/authorization. Even if these are seed values, shipping PII on an unauthenticated endpoint is a bad default.

**Fix:** Require auth and return only fields the caller is entitled to:

