const rateLimit = require('express-rate-limit');

app.disable('x-powered-by');
app.use(helmet());
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

const PORT = Number(process.env.PORT) || 3000;
if (!Number.isInteger(PORT) || PORT < 1 || PORT > 65535) {
  throw new Error('Invalid PORT');
}
```

## 4. Other Observations

- **`/users` returns hard-coded PII** — fine for a demo, but if this becomes real, require authentication (e.g., JWT middleware) and authorization checks before returning user data.
- **`new Date().toISOString()`** in `/health` is fine, but consider whether exposing server time is desirable (minor fingerprinting surface).
- **No logging middleware** — add `morgan` or `pino-http` so failed requests are auditable (important for detecting attacks).
- **No tests** — error paths especially benefit from integration tests using `supertest`.

## Summary Checklist

- [ ] Add global error-handling middleware + 404 handler
- [ ] Add `unhandledRejection` / `uncaughtException` / graceful shutdown
- [ ] Add `helmet`, `cors` (with allowlist), `express-rate-limit`
- [ ] Add `app.disable('x-powered-by')`
- [ ] Add `express.json({ limit: '10kb' })` before adding body routes
- [ ] Validate all params/query/body with `zod` or `express-validator`
- [ ] Read `PORT` from env with validation
- [ ] Add authn/authz before `/users` returns real data
- [ ] Add request logging (`morgan`/`pino-http`)

