  limit: z.coerce.number().int().min(1).max(100).default(25),
  offset: z.coerce.number().int().min(0).default(0),
});

app.get('/users', (req, res, next) => {
  try {
    const { limit, offset } = listUsersQuery.parse(req.query);
    const users = [
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
    ].slice(offset, offset + limit);
    // Do not leak PII (e.g., email) unless caller is authorized
    res.json(users);
  } catch (err) {
    next(err);
  }
