  res.status(404).json({ error: 'Not found' });
});

// Central error handler — 4 args signals Express it's an error middleware
app.use((err, req, res, next) => {
  // Log server-side, never leak internals to the client
  console.error(err);
  res.status(err.status || 500).json({ error: 'Internal server error' });
});

process.on('unhandledRejection', (reason) => console.error('unhandledRejection', reason));
process.on('uncaughtException', (err) => { console.error('uncaughtException', err); process.exit(1); });

const server = app.listen(3000, () => console.log('Server running on port 3000'));
server.on('error', (err) => { console.error('listen error', err); process.exit(1); });
```

## 2. No input validation / parsing limits

**Issue:** Currently no routes accept user input, but there is no `express.json()` or size limit configured. As soon as a POST/PUT route is added, the app will be vulnerable to large-body DoS and unvalidated input.

**Fix:** Add `express.json({ limit: '10kb' })` and validate with a schema library (e.g., `zod`, `joi`, `express-validator`). Example with `zod`:
```js
const { z } = require('zod');
app.use(express.json({ limit: '10kb' }));

const UserQuery = z.object({
  id: z.coerce.number().int().positive().max(1_000_000).optional(),
});

app.get('/users', (req, res, next) => {
  const parsed = UserQuery.safeParse(req.query);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid query' });
  // ... use parsed.data
});
```

Always validate/whitelist — never trust `req.query`, `req.params`, `req.body`, or headers directly.

## 3. Missing security headers and CORS policy

**Issue:** No `helmet`, no explicit CORS config. Responses ship with Express defaults (`X-Powered-By: Express`, no CSP, no HSTS).

**Fix:**
