`/users` and `/health` don't accept input yet, but as soon as they do (e.g. `/users/:id`, query filters, POST bodies) you need validation. Adopt a schema validator up front rather than retrofitting:

```js
const { z } = require('zod');

const IdParam = z.object({ id: z.coerce.number().int().positive().max(1e9) });

app.get('/users/:id', (req, res, next) => {
  const parsed = IdParam.safeParse(req.params);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid id' });
  // ...
});
```

