# Code Review: `app.js` — Error Handling, Input Validation & Security

Here's an analysis of the current `app.js` with concrete suggestions.

## Current Issues

### 1. **No global error handling**
Uncaught exceptions and rejected promises will crash the process or leak stack traces.

### 2. **No input validation middleware**
Routes don't validate query params, body, or headers — any future route expansion is vulnerable.

### 3. **Missing security headers**
No `helmet`, no CORS policy, no rate limiting.

### 4. **Sensitive data exposure**
`/users` returns raw email addresses without authentication/authorization.

### 5. **No body size limits**
If `express.json()` is added later without limits, it invites DoS via large payloads.

### 6. **Hardcoded port & no graceful shutdown**
`SIGTERM`/`SIGINT` aren't handled; in-flight requests are dropped.

### 7. **Unbounded `listen()` error**
If port 3000 is already in use, the error is unhandled.

---

## Suggested Rewrite

```javascript
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { query, validationResult } = require('express-validator');

const app = express();

// --- Security middleware ---
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '10kb' }));          // Cap body size
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Basic rate limit; tune per-route as needed
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// --- Routes ---
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get(
  '/users',
  // Example of validated query params (e.g., pagination)
  [
    query('limit').optional().isInt({ min: 1, max: 100 }).toInt(),
    query('offset').optional().isInt({ min: 0 }).toInt(),
  ],
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    try {
      // TODO: require auth before returning PII like email
      const users = [
        { id: 1, name: 'Alice' },
        { id: 2, name: 'Bob' },
      ];
      res.json(users);
    } catch (err) {
      next(err);
    }
  }
);

// --- 404 handler ---
app.use((_req, res) => res.status(404).json({ error: 'Not found' }));

// --- Centralized error handler (must have 4 args) ---
app.use((err, _req, res, _next) => {
  // Log full error server-side; return generic message to client
  console.error(err);
  const status = err.status || 500;
  res.status(status).json({
    error: status >= 500 ? 'Internal server error' : err.message,
  });
});

// --- Process-level safety nets ---
process.on('unhandledRejection', (reason) => {
  console.error('Unhandled rejection:', reason);
});
process.on('uncaughtException', (err) => {
  console.error('Uncaught exception:', err);
  process.exit(1);
});

// --- Startup & graceful shutdown ---
const PORT = Number(process.env.PORT) || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
server.on('error', (err) => {
  console.error('Server failed to start:', err);
  process.exit(1);
});

const shutdown = (signal) => {
  console.log(`${signal} received, shutting down gracefully...`);
  server.close(() => process.exit(0));
  setTimeout(() => process.exit(1), 10_000).unref();
};
['SIGTERM', 'SIGINT'].forEach((sig) => process.on(sig, () => shutdown(sig)));

module.exports = app;
